#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char str[256];
    char reversed[256];
    char str_lower[256];
    char reversed_lower[256];

    fgets(str, sizeof(str), stdin);

    int len = strlen(str);
    if (str[len - 1] == '\n') {
        str[len - 1] = '\0';
        len--;
    }

    for (int i = 0; i < len; i++) {
        reversed[i] = str[len - 1 - i];
    }
    reversed[len] = '\0';

    for (int i = 0; i < len; i++) {
        str_lower[i] = tolower((unsigned char)str[i]);
        reversed_lower[i] = tolower((unsigned char)reversed[i]);
    }
    str_lower[len] = '\0';
    reversed_lower[len] = '\0';

    printf("%s\n", reversed);

    if (strcmp(str_lower, reversed_lower) == 0) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }

    return 0;
}
